        // Gemini 결과에 브랜드+제품명이 모두 포함되어 있으면 Gemini 결과 우선
        if (cleanResult.includes(brandDetection.brand) && cleanResult.includes(brandDetection.product)) {
          if (cleanResult.length <= detectedName.length + 15) { // 너무 길지 않으면
            console.log('🎯 Gemini 결과 선택 (브랜드+제품 포함):', cleanResult);
            return cleanResult;
