        // 그렇지 않으면 직접 탐지된 결과 우선 사용
        console.log('🎯 직접 탐지 결과 선택:', detectedName);
        return detectedName;
      }
      
      console.log('🎯 Gemini 결과 사용:', cleanResult);
      return cleanResult || null;
      
    } catch (error) {
